1	//! Node abbreviation (BEHAVIOR.md §5): assigning short NAMES to complex terms
2	//! and rendering the legend table.
3	//!
4	//! Three things here are fully determined by observation and byte-tested:
5	//!   * [`prefix_for_symbol`] — the `PREFIX` derivation,
6	//!   * [`Abbreviator`] — per-prefix sequential numbering + nesting substitution,
7	//!   * [`legend_html`] — the exact `<TABLE …>` bytes incl. the 65-space hang indent.
8	//!
9	//! The *selection* of which sub-terms to abbreviate (§5c) and the canonical
10	//! numbering tie-break (§5b) are not fully determinable black-box; [`select`]
11	//! provides a documented heuristic and the caller controls numbering order.
12	
13	use std::collections::HashMap;
14	
15	use crate::term::Term;
16	
17	/// The opening tag of every legend table. Its byte length is the hang-indent
18	/// applied to continuation `<TR>` rows.
19	pub const TABLE_OPEN: &str =
20	    "<TABLE BORDER=\"1\" CELLBORDER=\"0\" CELLSPACING=\"3\" CELLPADDING=\"1\">";
21	
22	/// `PREFIX` for an abbreviation name: the first two *alphabetic* characters of
23	/// `name`, uppercased (one char if only one letter exists). Non-letters (digits,
24	/// `_`, `.`) are skipped. This is applied to the root symbol's *name* — for a
25	/// function `f(..)` that is `f`; for a constant `'c'` it is `c`; for a variable
26	/// `~v`/`$v`/`v` it is `v`; for an infix operator it is the operator's function
27	/// name (see [`Term::root_symbol_name`], which maps `^`→`exp`, `*`→`mult`,
28	/// `++`→`union`, `⊕`→`xor`).
29	///
30	/// Examples (all observed): `sign`→`SI`, `senc`→`SE`, `hash`→`HA`, `h2`→`H`,
31	/// `KDF`→`KD`, `pk`→`PK`, `aenc`→`AE`, `exp`→`EX`, `mult`→`MU`, `union`→`UN`,
32	/// `xor`→`XO`, `uninitialized`→`UN`, `F_status`→`FS`, `AMF_UE_NGAP_ID`→`AM`.
33	pub fn prefix_for_symbol(name: &str) -> String {
34	    name.chars()
35	        .filter(|c| c.is_ascii_alphabetic())
36	        .take(2)
37	        .flat_map(|c| c.to_uppercase())
38	        .collect()
39	}
40	
41	/// Assigns and remembers abbreviation names, de-duplicating identical terms and
42	/// numbering `1,2,3,…` per prefix in the order terms are [`Abbreviator::add`]ed.
43	///
44	/// Numbering order matches tamarin only where the canonical order is
45	/// unambiguous (see BEHAVIOR.md §5b); the caller decides insertion order.
46	#[derive(Default)]
47	pub struct Abbreviator {
48	    /// name -> the term it stands for, in insertion order.
49	    entries: Vec<(String, Term)>,
50	    /// canonical fully-expanded key -> assigned name (dedup).
51	    by_key: HashMap<String, String>,
52	    /// prefix -> next counter value.
53	    counters: HashMap<String, u32>,
54	}
55	
56	impl Abbreviator {
57	    pub fn new() -> Self {
58	        Self::default()
59	    }
60	
61	    /// Register `term` for abbreviation, returning its name. Terms that render
62	    /// identically (fully expanded) share one name.
63	    pub fn add(&mut self, term: Term) -> String {
64	        let key = term.render_full();
65	        if let Some(existing) = self.by_key.get(&key) {
66	            return existing.clone();
67	        }
68	        let prefix = prefix_for_symbol(&term.root_symbol_name());
69	        let n = self.counters.entry(prefix.clone()).or_insert(0);
70	        *n += 1;
71	        let name = format!("{}{}", prefix, n);
72	        self.by_key.insert(key, name.clone());
73	        self.entries.push((name.clone(), term));
74	        name
75	    }
76	
77	    /// The name for an already-registered term, if any (by full rendering).
78	    pub fn name_of(&self, term: &Term) -> Option<&str> {
79	        self.by_key.get(&term.render_full()).map(String::as_str)
80	    }
81	
82	    /// Legend rows `(name, expansion)` in insertion order. Each expansion renders
83	    /// the term one level with any registered *sub*-term replaced by its name
84	    /// (nesting, §5b: `EX1 = 'g'^MU1`). The expansion string is NOT yet
85	    /// HTML-escaped; [`legend_html`] escapes it.
86	    pub fn rows(&self) -> Vec<(String, String)> {
87	        self.entries
88	            .iter()
89	            .map(|(name, term)| (name.clone(), term.render_abbrev(&self.by_key)))
90	            .collect()
91	    }
92	
93	    /// Render the legend as the exact inner HTML of the `plain` node's label
94	    /// (the bytes between `label=<` and `>`). Empty if no entries.
95	    pub fn legend_html(&self) -> String {
96	        legend_html(&self.rows())
97	    }
98	
99	    pub fn is_empty(&self) -> bool {
100	        self.entries.is_empty()
101	    }
102	    pub fn len(&self) -> usize {
103	        self.entries.len()
104	    }
105	}
106	
107	/// HTML-escape a legend expansion: `&`→`&amp;`, `<`→`&lt;`, `>`→`&gt;`. Single
108	/// quotes and `* ^ ~ $ ⊕ ++` are left literal (as observed).
109	pub fn escape_expansion(s: &str) -> String {
110	    let mut out = String::with_capacity(s.len());
111	    for c in s.chars() {
112	        match c {
113	            '&' => out.push_str("&amp;"),
114	            '<' => out.push_str("&lt;"),
115	            '>' => out.push_str("&gt;"),
116	            _ => out.push(c),
117	        }
118	    }
119	    out
120	}
121	
122	/// Render one legend row's `<TR>…</TR>` (expansion is escaped here).
123	fn legend_row(name: &str, expansion: &str) -> String {
124	    format!(
125	        "<TR><TD ALIGN=\"LEFT\" VALIGN=\"TOP\"><FONT COLOR=\"#000000\">{}</FONT></TD> <TD ALIGN=\"LEFT\" VALIGN=\"TOP\">=</TD> <TD ALIGN=\"LEFT\" VALIGN=\"TOP\">{}</TD></TR>",
126	        name,
127	        escape_expansion(expansion),
128	    )
129	}
130	
131	/// The exact inner HTML for the legend `plain` node (between `label=<` and `>`):
132	/// `<TABLE …><TR>row0</TR>\n<65sp><TR>row1</TR>\n…<65sp><TR>rowN</TR></TABLE>`.
133	/// The first row is inline after the table tag; every continuation row is on its
134	/// own line indented by `TABLE_OPEN.len()` (= 65) spaces.
135	pub fn legend_html(rows: &[(String, String)]) -> String {
136	    if rows.is_empty() {
137	        return String::new();
138	    }
139	    let indent = " ".repeat(TABLE_OPEN.len());
140	    let mut s = String::new();
141	    s.push_str(TABLE_OPEN);
142	    for (i, (name, exp)) in rows.iter().enumerate() {
143	        if i > 0 {
144	            s.push('\n');
145	            s.push_str(&indent);
146	        }
147	        s.push_str(&legend_row(name, exp));
148	    }
149	    s.push_str("</TABLE>");
150	    s
151	}
152	
153	/// A documented, **best-effort** selection heuristic (see BEHAVIOR.md §5c —
154	/// byte-parity of the selection set is NOT claimed). Returns the sub-terms of
155	/// `roots` that this heuristic would abbreviate, bottom-up (inner before outer),
156	/// each non-atomic sub-term whose [`Term::size`] ≥ `min_size`, keeping only those
157	/// occurring at least `min_occ` times across `roots`.
158	pub fn select(roots: &[Term], min_size: usize, min_occ: usize) -> Vec<Term> {
159	    let mut counts: HashMap<String, (usize, Term)> = HashMap::new();
160	    for r in roots {
161	        r.for_each_subterm(&mut |t| {
162	            if !t.is_atomic() && t.size() >= min_size {
163	                let e = counts.entry(t.render_full()).or_insert((0, t.clone()));
164	                e.0 += 1;
165	            }
166	        });
167	    }
168	    let mut picked: Vec<Term> = counts
169	        .into_values()
170	        .filter(|(c, _)| *c >= min_occ)
171	        .map(|(_, t)| t)
172	        .collect();
173	    // bottom-up: smaller terms first so inner names are assigned before outer.
174	    picked.sort_by_key(|t| t.size());
175	    picked
176	}
177

1	//! A minimal term model, sufficient to drive abbreviation (naming + expansion
2	//! rendering). It is an independent design; it renders tamarin-like surface
3	//! syntax for the common term shapes observed in legend expansions
4	//! (variables, constants, pairs, `exp`/`mult`/`union`/`xor`, function apps).
5	//!
6	//! Faithful reproduction of the solver's full term pretty-printer (all operators,
7	//! precedence, line wrapping) is out of scope — see BEHAVIOR.md §3a/§5. The
8	//! covered shapes are byte-tested against captured legend rows.
9	
10	use std::collections::HashMap;
11	
12	/// A term. Variable kinds mirror tamarin's surface decorations.
13	#[derive(Clone, Debug, PartialEq, Eq)]
14	pub enum Term {
15	    /// Fresh variable, rendered `~name`.
16	    Fresh(String),
17	    /// Public variable, rendered `$name`.
18	    Pub(String),
19	    /// Bare message/temporal variable, rendered `name`.
20	    Msg(String),
21	    /// Public constant, rendered `'name'`.
22	    Const(String),
23	    /// Right-nested pair; rendered flattened as `<a, b, c>`.
24	    Pair(Box<Term>, Box<Term>),
25	    /// `exp(base, e)`, rendered `base^e` (the exponent carries its own parens
26	    /// when it is a product/sum).
27	    Exp(Box<Term>, Box<Term>),
28	    /// An associative-commutative operator rendered infix inside parentheses:
29	    /// `mult`→`*`, `union`→`++`, `xor`→`⊕`. `func` is the logical name used for
30	    /// the abbreviation prefix.
31	    Ac { func: String, op: String, args: Vec<Term> },
32	    /// Ordinary prefix application `func(a, b, …)`.
33	    App { func: String, args: Vec<Term> },
34	}
35	
36	impl Term {
37	    // ---- convenience constructors --------------------------------------
38	
39	    pub fn fresh(n: &str) -> Term {
40	        Term::Fresh(n.to_string())
41	    }
42	    pub fn pubv(n: &str) -> Term {
43	        Term::Pub(n.to_string())
44	    }
45	    pub fn msg(n: &str) -> Term {
46	        Term::Msg(n.to_string())
47	    }
48	    pub fn cst(n: &str) -> Term {
49	        Term::Const(n.to_string())
50	    }
51	    pub fn app(func: &str, args: Vec<Term>) -> Term {
52	        Term::App { func: func.to_string(), args }
53	    }
54	    pub fn exp(base: Term, e: Term) -> Term {
55	        Term::Exp(Box::new(base), Box::new(e))
56	    }
57	    pub fn mult(args: Vec<Term>) -> Term {
58	        Term::Ac { func: "mult".into(), op: "*".into(), args }
59	    }
60	    pub fn union(args: Vec<Term>) -> Term {
61	        Term::Ac { func: "union".into(), op: "++".into(), args }
62	    }
63	    pub fn xor(args: Vec<Term>) -> Term {
64	        Term::Ac { func: "xor".into(), op: "\u{2295}".into(), args }
65	    }
66	    /// Build a flattened tuple `<a, b, c>` from ≥1 elements (right-nested pairs).
67	    pub fn tuple(mut elems: Vec<Term>) -> Term {
68	        let last = elems.pop().expect("tuple needs ≥1 element");
69	        elems.into_iter().rev().fold(last, |acc, e| Term::Pair(Box::new(e), Box::new(acc)))
70	    }
71	
72	    // ---- naming --------------------------------------------------------
73	
74	    /// The root symbol's *name*, whose first two letters give the abbreviation
75	    /// prefix (see [`crate::abbrev::prefix_for_symbol`]).
76	    pub fn root_symbol_name(&self) -> String {
77	        match self {
78	            Term::Fresh(n) | Term::Pub(n) | Term::Msg(n) | Term::Const(n) => n.clone(),
79	            Term::Pair(..) => "pair".to_string(),
80	            Term::Exp(..) => "exp".to_string(),
81	            Term::Ac { func, .. } => func.clone(),
82	            Term::App { func, .. } => func.clone(),
83	        }
84	    }
85	
86	    /// Leaf terms (variables/constants) are atomic; everything else is not.
87	    pub fn is_atomic(&self) -> bool {
88	        matches!(self, Term::Fresh(_) | Term::Pub(_) | Term::Msg(_) | Term::Const(_))
89	    }
90	
91	    /// Number of term nodes (atoms + operators) — a simple complexity measure.
92	    pub fn size(&self) -> usize {
93	        match self {
94	            Term::Fresh(_) | Term::Pub(_) | Term::Msg(_) | Term::Const(_) => 1,
95	            Term::Pair(a, b) => 1 + a.size() + b.size(),
96	            Term::Exp(a, b) => 1 + a.size() + b.size(),
97	            Term::Ac { args, .. } | Term::App { args, .. } => {
98	                1 + args.iter().map(Term::size).sum::<usize>()
99	            }
100	        }
101	    }
102	
103	    /// Visit this term and every sub-term (pre-order).
104	    pub fn for_each_subterm(&self, f: &mut dyn FnMut(&Term)) {
105	        f(self);
106	        match self {
107	            Term::Pair(a, b) | Term::Exp(a, b) => {
108	                a.for_each_subterm(f);
109	                b.for_each_subterm(f);
110	            }
111	            Term::Ac { args, .. } | Term::App { args, .. } => {
112	                for a in args {
113	                    a.for_each_subterm(f);
114	                }
115	            }
116	            _ => {}
117	        }
118	    }
119	
120	    // ---- rendering -----------------------------------------------------
121	
122	    /// Fully-expanded surface rendering (no abbreviations). Used as the dedup key.
123	    pub fn render_full(&self) -> String {
124	        self.render_with(&|t| t.render_full())
125	    }
126	
127	    /// Render this term's expansion, replacing any *registered* sub-term (present
128	    /// in `table`, keyed by its full rendering) with its abbreviation name. The
129	    /// top-level term itself is always rendered structurally.
130	    pub fn render_abbrev(&self, table: &HashMap<String, String>) -> String {
131	        self.render_with(&|t| t.substitute(table))
132	    }
133	
134	    /// Rendering used for children during abbreviation: a registered term yields
135	    /// its name, otherwise it renders structurally (recursing on its children).
136	    fn substitute(&self, table: &HashMap<String, String>) -> String {
137	        if let Some(name) = table.get(&self.render_full()) {
138	            return name.clone();
139	        }
140	        self.render_with(&|t| t.substitute(table))
141	    }
142	
143	    /// Structural rendering; `child` renders each immediate sub-term.
144	    fn render_with(&self, child: &dyn Fn(&Term) -> String) -> String {
145	        match self {
146	            Term::Fresh(n) => format!("~{}", n),
147	            Term::Pub(n) => format!("${}", n),
148	            Term::Msg(n) => n.clone(),
149	            Term::Const(n) => format!("'{}'", n),
150	            Term::Pair(..) => {
151	                let elems = self.pair_spine();
152	                let parts: Vec<String> = elems.iter().map(|t| child(t)).collect();
153	                format!("<{}>", parts.join(", "))
154	            }
155	            Term::Exp(base, e) => format!("{}^{}", child(base), child(e)),
156	            Term::Ac { op, args, .. } => {
157	                let parts: Vec<String> = args.iter().map(|t| child(t)).collect();
158	                format!("({})", parts.join(op))
159	            }
160	            Term::App { func, args } => {
161	                let parts: Vec<String> = args.iter().map(|t| child(t)).collect();
162	                format!("{}({})", func, parts.join(", "))
163	            }
164	        }
165	    }
166	
167	    /// Flatten a right-nested pair into its element spine.
168	    fn pair_spine(&self) -> Vec<&Term> {
169	        let mut out = Vec::new();
170	        let mut cur = self;
171	        while let Term::Pair(a, b) = cur {
172	            out.push(a.as_ref());
173	            cur = b.as_ref();
174	        }
175	        out.push(cur);
176	        out
177	    }
178	}
179

1	//! # graph-clean
2	//!
3	//! A clean-room reimplementation of the tamarin-prover web-UI constraint-system
4	//! graph payload — the graphviz DOT text served at
5	//! `/thy/trace/N/interactive-graph-def/proof/…`.
6	//!
7	//! Everything here was derived from BLACK-BOX observation of captured payloads
8	//! and live probing of the compiled server; see `workspace/BEHAVIOR.md` for the
9	//! observed spec and `workspace/QUERIES.log` for the oracle interactions. No
10	//! tamarin-prover source was consulted.
11	//!
12	//! ## What it does
13	//! * [`model`] — an independent graph data model (nodes, edges, clusters, legend).
14	//! * [`dot::to_dot`] — a **byte-exact** DOT serializer for that model.
15	//! * [`term`] — a small term model backing abbreviation expansions.
16	//! * [`abbrev`] — node abbreviation: prefix derivation, per-prefix numbering,
17	//!   and byte-exact legend-table HTML.
18	//!
19	//! ## Clustering / simplification trigger
20	//! The compact (clustered) header is used exactly when a graph carries a node
21	//! with a role other than `Undefined`; [`model::Graph::infer_header`] applies
22	//! this observed rule.
23	//!
24	//! ```
25	//! use graph_clean::model::*;
26	//! let mut g = Graph::new(Header::Simple);
27	//! g.push(Stmt::Node(Node::ellipse("n7", Ellipse::new("#vf : isend"))));
28	//! let dot = graph_clean::dot::to_dot(&g);
29	//! assert!(dot.starts_with("digraph \"G\" {\nnodesep=\"0.3\";"));
30	//! assert!(dot.ends_with("\n\n}\n"));
31	//! ```
32	
33	pub mod abbrev;
34	pub mod dot;
35	pub mod model;
36	pub mod term;
37	
38	pub use dot::to_dot;
39	pub use model::{Graph, Header};
40	pub use term::Term;
41

1	//! Abbreviation + clustering tests, grounded in observed payloads
2	//! (BEHAVIOR.md §4, §5).
3	
4	use graph_clean::abbrev::{legend_html, prefix_for_symbol, Abbreviator, TABLE_OPEN};
5	use graph_clean::model::*;
6	use graph_clean::term::Term;
7	
8	/// Extract the inner HTML of the first `plain` legend node (bytes between
9	/// `label=<` and `>];`).
10	fn legend_inner(dot: &str) -> String {
11	    let anchor = dot.find("shape=\"plain\",label=<").unwrap();
12	    let start = anchor + dot[anchor..].find("label=<").unwrap() + "label=<".len();
13	    let end = start + dot[start..].find(">];").unwrap();
14	    dot[start..end].to_string()
15	}
16	
17	#[test]
18	fn table_open_tag_is_65_bytes() {
19	    // The legend hang-indent equals this tag's byte length (BEHAVIOR.md §5a).
20	    assert_eq!(TABLE_OPEN.len(), 65);
21	}
22	
23	#[test]
24	fn prefix_rule_matches_observed_names() {
25	    // (root symbol name, observed prefix) pairs taken from the corpus legend.
26	    let cases = [
27	        ("sign", "SI"),
