36	        ("aenc", "AE"),
37	        ("aead", "AE"),
38	        ("adec", "AD"),
39	        ("pmult", "PM"),
40	        ("plus", "PL"),
41	        ("pdec", "PD"),
42	        ("inv", "IN"),
43	        ("mac", "MA"),
44	        ("blind", "BL"),
