#!/usr/bin/env python3
"""True occurrence count of each abbreviated (positive) term, via recursive
nesting accounting. occ(N) = displayed uses of N in node labels
+ sum over parents M of (count of N in M.rhs)*occ(M)."""
import re, glob, os, sys, collections

CORP="/home/kamilner/tamarin-cleanroom/graphdot/oracle/dot_corpus"

def decode_html(s):
    return s.replace('&lt;','<').replace('&gt;','>').replace('&#32;',' ').replace('&amp;','&')
def strip_br(s):
    return re.sub(r'<BR ALIGN="LEFT"/>\s*',' ',s)

LEGEND_ROW=re.compile(r'FONT COLOR="#000000">(.*?)</FONT></TD> <TD ALIGN="LEFT" VALIGN="TOP">=</TD> <TD ALIGN="LEFT" VALIGN="TOP">(.*?)</TD></TR>')

def parse_legend(dot):
    d={}
    for m in LEGEND_ROW.finditer(dot):
        d[m.group(1)]=strip_br(decode_html(m.group(2)))
    return d

def legend_span(dot):
    i=dot.find('rank="sink"')
    if i<0: return None
    j=dot.rfind('{',0,i); k=dot.find('}',i)
    return (j,k)

def node_region(dot):
    span=legend_span(dot)
    if span: return dot[:span[0]]+dot[span[1]:]
    return dot

def fullmap(legend):
    full={}
    names=sorted(legend,key=len,reverse=True)
    pat=re.compile(r'\b('+'|'.join(re.escape(n) for n in names)+r')\b') if names else None
    def resolve(n,stack):
        if n in full: return full[n]
        rhs=legend[n]
        if pat:
            rhs=pat.sub(lambda m: resolve(m.group(1),stack|{m.group(1)}) if (m.group(1) in legend and m.group(1) not in stack) else m.group(1), rhs)
        full[n]=rhs; return rhs
    for n in legend: resolve(n,{n})
    return full

def true_occ(legend, region):
    """returns name->occ (int)."""
    names=list(legend)
    # displayed uses in node region
    disp={}
    for n in names:
        disp[n]=len(re.findall(r'\b'+re.escape(n)+r'\b', region))
    # count of n inside m.rhs
    inside={}  # (n,m)->count
    for m in names:
        for n in names:
            if n==m: continue
            c=len(re.findall(r'\b'+re.escape(n)+r'\b', legend[m]))
            if c: inside[(n,m)]=c
    # topological: occ(N)=disp(N)+ sum_m inside[(N,m)]*occ(m)
    occ={}
    # memoized recursion (DAG: a name's rhs only refs names, acyclic)
    def compute(n, stack):
        if n in occ: return occ[n]
        total=disp[n]
        for m in names:
            if (n,m) in inside and m not in stack:
                total += inside[(n,m)]*compute(m, stack|{m})
        occ[n]=total
        return total
    for n in names: compute(n,{n})
    return occ

def is_atom(rhs):
    return bool(re.fullmatch(r"[~$]?[A-Za-z_'][A-Za-z_0-9.]*'?", rhs) or re.fullmatch(r"'[^']*'", rhs))

def main():
    files=sorted(glob.glob(os.path.join(CORP,'*.dot')))
    limit=int(sys.argv[1]) if len(sys.argv)>1 else 800
    rows=[]
    nf=0
    for fn in files[:limit]:
        dot=open(fn,encoding='utf-8',errors='replace').read()
        if 'TABLE BORDER' not in dot: continue
        legend=parse_legend(dot)
        if not legend: continue
        nf+=1
        fm=fullmap(legend)
        region=node_region(dot)
        occ=true_occ(legend, region)
        for n,rhs in legend.items():
            rows.append((len(fm[n]), occ[n], is_atom(rhs), n, rhs, os.path.basename(fn)))
    print(f"files:{nf} positives:{len(rows)}")
    print("min length:", min(r[0] for r in rows))
    oc=collections.Counter(r[1] for r in rows)
    print("true-occ distribution:", sorted(oc.items())[:15])
    lt2=[r for r in rows if r[1]<2]
    print(f"positives with true occ<2: {len(lt2)}")
    for r in lt2[:25]:
        print(f"   occ={r[1]} len={r[0]} atom={r[2]} {r[3]}={r[4][:50]!r}  [{r[5]}]")
if __name__=='__main__': main()

