#!/usr/bin/env python3
"""Occurrence over the FULL system = graph node facts (dot) + sequent (json).
Substring counting on whitespace-normalized, fully-expanded combined text.
Clean-room: reads only oracle/captured_responses/*.hs.json (captured OUTPUT)."""
import json, re, glob, os, sys, collections

CAP="/home/kamilner/tamarin-cleanroom/graphdot/oracle/captured_responses"

def decode(s):
    return (s.replace('&lt;','<').replace('&gt;','>').replace('&#32;',' ')
             .replace('&#39;',"'").replace('&nbsp;',' ').replace('&amp;','&'))
def stripbr(s): return re.sub(r'<BR ALIGN="LEFT"/>\s*',' ',s)
def norm_ws(s): return re.sub(r'\s+',' ',s).strip()

ROW=re.compile(r'FONT COLOR="#000000">(.*?)</FONT></TD> <TD ALIGN="LEFT" VALIGN="TOP">=</TD> <TD ALIGN="LEFT" VALIGN="TOP">(.*?)</TD></TR>')

def parse_legend(dot):
    return {m.group(1): stripbr(decode(m.group(2))) for m in ROW.finditer(dot)}

def legend_span(dot):
    i=dot.find('rank="sink"')
    if i<0: return None
    return (dot.rfind('{',0,i), dot.find('}',i))

def dot_node_text(dot):
    span=legend_span(dot); body=dot[:span[0]]+dot[span[1]:] if span else dot
    parts=[]
    for m in re.finditer(r'shape="record",label="((?:[^"\\]|\\.)*)"', body):
        lab=m.group(1)
        lab=(lab.replace('\\<','<').replace('\\>','>').replace('\\{','{')
                .replace('\\}','}').replace('\\|',' ').replace('\\l',' ').replace('&nbsp;',' '))
        lab=re.sub(r'<n\d+>','',lab)
        parts.append(lab)
    for m in re.finditer(r'\blabel="((?:[^"\\]|\\.)*)",shape="ellipse"', body):
        parts.append(m.group(1))
    return ' '.join(parts)

def strip_tags(h):
    h=re.sub(r'<br\s*/?>','\n',h)
    h=re.sub(r'<[^>]+>',' ',h)
    return decode(h)

def sequent_text(pj_html):
    txt=strip_tags(pj_html)
    i=txt.find('Constraint system')
    return txt[i:] if i>=0 else txt

def fullmap(legend):
    full={}; names=sorted(legend,key=len,reverse=True)
    pat=re.compile(r'\b('+'|'.join(re.escape(n) for n in names)+r')\b') if names else None
    def res(n,st):
        if n in full: return full[n]
        rhs=legend[n]
        if pat: rhs=pat.sub(lambda m:res(m.group(1),st|{m.group(1)}) if (m.group(1) in legend and m.group(1) not in st) else m.group(1), rhs)
        full[n]=rhs; return rhs
    for n in legend: res(n,{n})
    return full

def expand_text(text, full):
    if not full: return text
    names=sorted(full,key=len,reverse=True)
    pat=re.compile(r'\b('+'|'.join(re.escape(n) for n in names)+r')\b')
    prev=None; cur=text; it=0
    while prev!=cur and it<25:
        prev=cur; cur=pat.sub(lambda m:full[m.group(1)],cur); it+=1
    return cur

def count_sub(hay,needle):
    if not needle: return 0
    c=0;i=0;L=len(needle)
    while True:
        j=hay.find(needle,i)
        if j<0: break
        c+=1;i=j+L
    return c

def is_atom(rhs):
    return bool(re.fullmatch(r"[~$]?[A-Za-z_'][A-Za-z_0-9.]*'?", rhs) or re.fullmatch(r"'[^']*'", rhs))

def main():
    files=sorted(glob.glob(os.path.join(CAP,'*.hs.json')), key=os.path.getsize)
    limit=int(sys.argv[1]) if len(sys.argv)>1 else 15
    rows=[]; npairs=0
    for f in files[:limit]:
        try: d=json.load(open(f))
        except: continue
        m=d['manifest']
        for url,resp in m.items():
            if 'interactive-graph-def' not in url: continue
            dot=resp.get('body','')
            if 'TABLE BORDER' not in dot: continue
            legend=parse_legend(dot)
            if not legend: continue
            purl=url.replace('/interactive-graph-def/','/main/')
            pr=m.get(purl)
            seq=''
            if pr:
                try: seq=sequent_text(json.loads(pr['body']).get('html',''))
                except: seq=''
            fm=fullmap(legend)
            combined=norm_ws(dot_node_text(dot)+' '+seq)
            combined=norm_ws(expand_text(combined, fm))
            npairs+=1
            for n,rhs in legend.items():
                full=norm_ws(fm[n])
                occ=count_sub(combined, full)
                rows.append((len(fm[n]), occ, is_atom(rhs), n, rhs, os.path.basename(f)))
    print(f"pairs:{npairs} positives:{len(rows)}")
    print("min length:", min(r[0] for r in rows))
    print("full-system occ dist:", sorted(collections.Counter(r[1] for r in rows).items())[:12])
    lt2=[r for r in rows if r[1]<2]
    print(f"positives with combined occ<2: {len(lt2)} ({100*len(lt2)/len(rows):.1f}%)")
    for r in lt2[:30]:
        print(f"   occ={r[1]} len={r[0]} atom={r[2]} {r[3]}={r[4][:45]!r} [{r[5][:12]}]")
if __name__=='__main__': main()

