import re

# A term string uses: ident, ~v, $v, #v, %v, 'const', f(...), <...>, ^ , (..*..),
# (..++..), (..(+)..) xor. Idents: [A-Za-z_][A-Za-z_0-9]*  with optional .N suffixes.
IDENT = re.compile(r"[A-Za-z_][A-Za-z_0-9]*(?:\.[0-9]+)*")

