"""Labeled dataset for the abbreviation SELECTION rule.
Candidates = TERM subterms of graph node-fact arguments (fact heads excluded).
occ counted over graph cells + sequent (json). Label = in legend.
Clean-room: reads only captured OUTPUT (dot bodies + json bodies)."""
import json, re, glob, os, sys, collections
from parser import SpanParser, IDENT

CAP="/home/kamilner/tamarin-cleanroom/graphdot/oracle/captured_responses"

def decode(s):
    return (s.replace('&lt;','<').replace('&gt;','>').replace('&#32;',' ')
             .replace('&#39;',"'").replace('&nbsp;',' ').replace('&amp;','&'))
def stripbr(s): return re.sub(r'<BR ALIGN="LEFT"/>\s*',' ',s)
def norm(s): return re.sub(r'\s+',' ',s).strip()

ROW=re.compile(r'FONT COLOR="#000000">(.*?)</FONT></TD> <TD ALIGN="LEFT" VALIGN="TOP">=</TD> <TD ALIGN="LEFT" VALIGN="TOP">(.*?)</TD></TR>')

def parse_legend(dot):
    return {m.group(1): stripbr(decode(m.group(2))) for m in ROW.finditer(dot)}

def legend_span(dot):
    i=dot.find('rank="sink"')
    if i<0: return None
    return (dot.rfind('{',0,i), dot.find('}',i))

def unescape_record(lab):
    return (lab.replace('\\<','<').replace('\\>','>').replace('\\{','{')
              .replace('\\}','}').replace('\\l',' ').replace('&nbsp;',' '))

def get_cells(dot):
    """Return list of cell strings from all record + ellipse labels (excl legend)."""
    span=legend_span(dot); body=dot[:span[0]]+dot[span[1]:] if span else dot
    cells=[]
    for m in re.finditer(r'shape="record",label="((?:[^"\\]|\\.)*)"', body):
        lab=unescape_record(m.group(1))
        # split into cells on record separators | and braces
        for piece in re.split(r'\\\||\{|\}', lab):
            piece=re.sub(r'<n\d+>','',piece).strip()
            if piece: cells.append(piece)
    for m in re.finditer(r'\blabel="((?:[^"\\]|\\.)*)",shape="ellipse"', body):
        cells.append(m.group(1).strip())
    return cells

def fact_arg_regions(cell):
    """Yield argument-strings of TOP-LEVEL fact calls in a cell (fact heads excluded)."""
    c=cell.strip()
    c=re.sub(r'^#[\w.]+\s*:\s*','',c)          # temporal prefix
    c=re.sub(r'\s*@\s*#[\w.]+.*$','',c)         # action timepoint (+ trailing)
    c=re.sub(r'\s*▶[₀-₉0-9]*\s*#[\w.]+.*$','',c)  # premise marker
    c=c.strip()
    out=[]
    # rule-instance with action list: Name[ factlist ]
    mb=re.match(r'^!?[A-Za-z_][\w]*\s*\[(.*)\]\s*$', c, re.S)
    if mb:
        inner=mb.group(1)
        # split factlist at top-level commas
        for fs in split_top(inner, ','):
            fs=fs.strip()
            ma=re.match(r'^!?[A-Za-z_][\w]*\s*\((.*)\)\s*$', fs, re.S)
            if ma: out.append(ma.group(1))
        return out
    # single fact: Name( args )
    ma=re.match(r'^!?[A-Za-z_][\w]*\s*\((.*)\)\s*$', c, re.S)
    if ma:
        out.append(ma.group(1)); return out
    return out

def split_top(s, sep):
    """Split s on sep at bracket depth 0 (considering () <> [])."""
    depth=0; cur=''; res=[]
    for ch in s:
        if ch in '(<[': depth+=1
        elif ch in ')>]': depth-=1
        if ch==sep and depth==0:
            res.append(cur); cur=''
        else: cur+=ch
    res.append(cur); return res

def fullmap(legend):
    full={}; names=sorted(legend,key=len,reverse=True)
    pat=re.compile(r'\b('+'|'.join(re.escape(n) for n in names)+r')\b') if names else None
    def res(n,st):
        if n in full: return full[n]
        rhs=legend[n]
        if pat: rhs=pat.sub(lambda m:res(m.group(1),st|{m.group(1)}) if (m.group(1) in legend and m.group(1) not in st) else m.group(1), rhs)
        full[n]=rhs; return rhs
