    combined=norm(expand_str(' '.join(graph_terms_text)+' '+seq, fm))
    # distinct candidates by fully-expanded normalized string
    seen={}
    for src in cand_src:
        full=norm(expand_str(src, fm))
        if not full: continue
        if full not in seen:
            seen[full]=full
    for full in seen:
        length=len(full)
        occ=count_sub(combined, full)
        label = full in legend_full_norm
        agg.append((length, occ, label, full))

def main():
    files=sorted(glob.glob(os.path.join(CAP,'*.hs.json')), key=os.path.getsize)
    limit=int(sys.argv[1]) if len(sys.argv)>1 else 15
    agg=[]; npairs=0
    for f in files[:limit]:
        try: d=json.load(open(f))
        except: continue
        m=d['manifest']
        for url,resp in m.items():
            if 'interactive-graph-def' not in url: continue
            dot=resp.get('body','')
            if 'TABLE BORDER' not in dot: continue
            purl=url.replace('/interactive-graph-def/','/main/')
            seq_html=''
            pr=m.get(purl)
            if pr:
                try: seq_html=json.loads(pr['body']).get('html','')
                except: pass
            process_pair(dot, seq_html, agg)
            npairs+=1
    print(f"pairs:{npairs} distinct-candidate rows:{len(agg)}")
    # evaluate rule len>=10 and occ>=2
    T=10
    tp=fp=tn=fn=0
    fps=[]; fns=[]
    for (L,O,lab,full) in agg:
        pred = (L>=T and O>=2)
        if pred and lab: tp+=1
        elif pred and not lab: fp+=1; fps.append((L,O,full))
        elif not pred and lab: fn+=1; fns.append((L,O,full))
        else: tn+=1
    tot=len(agg)
    print(f"rule (len>=10 AND occ>=2): TP={tp} FP={fp} TN={tn} FN={fn}")
    print(f"accuracy={100*(tp+tn)/tot:.2f}%  (of {tot})")
    print(f"among ACTUAL positives seen as candidates: {tp+fn}, recall={100*tp/(tp+fn) if tp+fn else 0:.2f}%")
    print(f"among PREDICTED positive: {tp+fp}, precision={100*tp/(tp+fp) if tp+fp else 0:.2f}%")
    print("--- FALSE POSITIVES (pred abbrev, actually not) sample ---")
    for L,O,full in fps[:25]: print(f"   len={L} occ={O} {full[:60]!r}")
    print(f"   (total FP {len(fps)})")
    print("--- FALSE NEGATIVES (actual abbrev, rule missed) sample ---")
    for L,O,full in fns[:25]: print(f"   len={L} occ={O} {full[:60]!r}")
    print(f"   (total FN {len(fns)})")
if __name__=='__main__': main()

