#!/usr/bin/env python3
"""AST parser for tamarin printed terms, with source spans + structural features.
Clean-room: operates only on captured OUTPUT strings passed in."""
import re
IDENT = re.compile(r"[A-Za-z_][A-Za-z_0-9]*(?:\.[0-9]+)*")

class Node:
    __slots__=('kind','src','children','expbase')
    def __init__(self,kind,src,children):
        self.kind=kind; self.src=src; self.children=children; self.expbase=False

class Parser:
    def __init__(self,s): self.s=s; self.i=0; self.n=len(s)
    def ws(self):
        while self.i<self.n and self.s[self.i] in ' \t\n': self.i+=1
    def peek(self): return self.s[self.i] if self.i<self.n else ''
    def term(self):
        self.ws(); start=self.i
        base=self.primary()
        node=base
        while True:
            self.ws()
            if self.peek()=='^':
                self.i+=1
                e=self.primary()
                if base is not None: base.expbase=True
                node=Node('exp', self.s[start:self.i], [c for c in [base,e] if c is not None])
                base=node
            else: break
        # fix src for exp chain
        if node is not None: node.src=self.s[start:self.i]
        return node
    def primary(self):
        self.ws(); c=self.peek(); start=self.i
        if c=='<':
            self.i+=1; kids=self.arglist('>')
            return Node('tuple', self.s[start:self.i], kids)
        if c=='(':
            self.i+=1; kids=self.arglist(')')
            # a paren groups an AC expr; if single child, unwrap
            if len(kids)==1:
                return kids[0]
            return Node('ac', self.s[start:self.i], kids)
        if c=="'":
            self.i+=1
            while self.i<self.n and self.s[self.i]!="'": self.i+=1
            if self.i<self.n: self.i+=1
            return Node('const', self.s[start:self.i], [])
        if c in '~$#%':
            self.i+=1; m=IDENT.match(self.s,self.i)
            if m: self.i=m.end()
            return Node('var', self.s[start:self.i], [])
        m=IDENT.match(self.s,self.i)
        if m:
            self.i=m.end(); self.ws()
            if self.peek()=='(':
                self.i+=1; kids=self.arglist(')')
                return Node('app', self.s[start:self.i], kids)
            return Node('name', self.s[start:self.i], [])  # bare ident (var/const/abbrev-ref)
        self.i+=1; return None
    def arglist(self, close):
        kids=[]; self.ws()
        if self.peek()==close:
            self.i+=1; return kids
        while True:
            t=self.term()
            if t is not None: kids.append(t)
            self.ws(); c=self.peek()
            if c==',': self.i+=1; continue
            if c in '*+':
                while self.peek() in '*+': self.i+=1
                continue
            if c=='⊕': self.i+=1; continue
            if c==close: self.i+=1; return kids
            if c=='': return kids
            self.i+=1

def parse_args(argstr):
    """Parse a fact-argument string into top-level term nodes."""
    p=Parser('('+argstr+')')
    p.i=1
    return p.arglist(')')

def walk(node, out):
    out.append(node)
    for c in node.children: walk(c, out)

