def split_top(s, sep):
    depth=0; cur=''; res=[]
    for ch in s:
        if ch in '(<[': depth+=1
        elif ch in ')>]': depth-=1
        if ch==sep and depth==0: res.append(cur); cur=''
        else: cur+=ch
    res.append(cur); return res
def fact_arg_regions(cell):
    c=cell.strip()
    c=re.sub(r'^#[\w.]+\s*:\s*','',c)
