/// A documented, **best-effort** selection heuristic (see BEHAVIOR.md §5c —
/// byte-parity of the selection set is NOT claimed). Returns the sub-terms of
/// `roots` that this heuristic would abbreviate, bottom-up (inner before outer),
/// each non-atomic sub-term whose [`Term::size`] ≥ `min_size`, keeping only those
/// occurring at least `min_occ` times across `roots`.
pub fn select(roots: &[Term], min_size: usize, min_occ: usize) -> Vec<Term> {
    let mut counts: HashMap<String, (usize, Term)> = HashMap::new();
    for r in roots {
        r.for_each_subterm(&mut |t| {
            if !t.is_atomic() && t.size() >= min_size {
                let e = counts.entry(t.render_full()).or_insert((0, t.clone()));
                e.0 += 1;
            }
        });
    }
    let mut picked: Vec<Term> = counts
        .into_values()
        .filter(|(c, _)| *c >= min_occ)
        .map(|(_, t)| t)
        .collect();
    // bottom-up: smaller terms first so inner names are assigned before outer.
    picked.sort_by_key(|t| t.size());
    picked
}

